/*-----------------------------------------------------------------------------------------------------------------------------------*/
/*  Function Definitions                                                                                                             */
/*-----------------------------------------------------------------------------------------------------------------------------------*/
/*===================================================================================================================================*/
/*  static U4      u4_s_AlertS_scbSrcchk(const U1 u1_a_VOM, const U4 u4_a_IGN_TM, const U1 u1_a_LAS)                                 */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      -                                                                                                                */
/*  Return:         -                                                                                                                */
/*===================================================================================================================================*/
static U4      u4_s_AlertS_scbSrcchk(const U1 u1_a_VOM, const U4 u4_a_IGN_TM, const U1 u1_a_LAS)
{
#ifdef ComConf_ComSignal_SCSACCEL
    static const U1 u1_s_ALERT_S_SCB_LSB_SCSACCEL = (U1)2U;
#endif /* ComConf_ComSignal_SCSACCEL */
    static const U1 u1_s_ALERT_S_SCB_LSB_MSGSTS   = (U1)4U;
    static const U2 u2_s_ALERT_S_SCB_THRESH_TO    = ((U2)5000U / (U2)OXCAN_MAIN_TICK);
    U1              u1_t_msgsts;
    U1              u1_t_sgnl;
    U4              u4_t_src_chk;

    u1_t_msgsts   = u1_g_oXCANRxStat((U2)OXCAN_PDU_RX_CAN_ABG1S01_RXCH0,
                                          (U2)OXCAN_RX_SYS_NRX_IGR | (U2)OXCAN_RX_SYS_TOE_IGR,
                                          u2_s_ALERT_S_SCB_THRESH_TO) & ((U1)COM_TIMEOUT | (U1)COM_NO_RX);

    u1_t_sgnl     = (U1)0U;
#ifdef ComConf_ComSignal_SCSBZR
    (void)Com_ReceiveSignal(ComConf_ComSignal_SCSBZR, &u1_t_sgnl);
#endif /* ComConf_ComSignal_SCSBZR */
    u4_t_src_chk  = (U4)u1_t_sgnl;

#ifdef ComConf_ComSignal_SCSACCEL
    u1_t_sgnl     = (U1)0U;
    (void)Com_ReceiveSignal(ComConf_ComSignal_SCSACCEL, &u1_t_sgnl);
    u4_t_src_chk |= (U4)u1_t_sgnl   << u1_s_ALERT_S_SCB_LSB_SCSACCEL;
#endif /* ComConf_ComSignal_SCSACCEL */

    u4_t_src_chk |= (U4)u1_t_msgsts << u1_s_ALERT_S_SCB_LSB_MSGSTS;

    return(u4_t_src_chk);
}

